### 2. `src/routes/_authed/index.tsx`

**Imports:** `redirect` from `@tanstack/react-router`; `createServerFn` from `@tanstack/react-start`; `getAppBootstrapData` from `@/server/app-bootstrap`; `OrgApiError` from `@/server/error`.

**Pattern:** `getDashboardData` calls `getAppBootstrapData()`, redirects to `/login` if there is no `currentTenant`, and on `OrgApiError` **401** in the catch block.

```40:65:/Users/duhl/git/ui/apps/org-next/src/routes/_authed/index.tsx
const getDashboardData = createServerFn({ method: "GET" }).handler(async () => {
  try {
    const bootstrap = await getAppBootstrapData();
    if (!bootstrap?.currentTenant) {
      throw redirect({ to: "/login" });
    }

    const campaigns = (await fetchCampaignsList()) ?? [];
    const simplified = campaigns.map((c) => ({ id: c.id, name: c.name }));

    return {
      campaigns: simplified,
      cards: {
        campaigns: simplified.length,
        payouts: 7,
        transactions: 428,
      },
    } satisfies DashboardPageData;
  } catch (error) {
    if (error instanceof OrgApiError && error.status === 401) {
      throw redirect({ to: "/login" });
    }

    throw error;
  }
});
```

