### 3. `src/routes/_authed/campaigns/-campaigns.ts`

**Imports:** `redirect`, `notFound`, `isNotFound` from `@tanstack/react-router`; `createServerFn` from `@tanstack/react-start`; `getAppBootstrapData` from `../../../server/app-bootstrap`; `OrgApiError` from `../../../server/error`; `getOrgApiJson`, `postOrgApiJson`, `putOrgApiJson` from org API helpers.

**Pattern:** Helper `requireBootstrapWithTenant()` calls `getAppBootstrapData()` and returns `null` if there is no tenant (no redirect in the helper itself). Several handlers return `null` when context is missing. **`updateCampaign`**, **`getCampaignDetail`**, and **`createCampaign`** throw `redirect({ to: "/login" })` on **401**.

```17:26:/Users/duhl/git/ui/apps/org-next/src/routes/_authed/campaigns/-campaigns.ts
async function requireBootstrapWithTenant(): Promise<{
  tenant: Tenant;
} | null> {
  const bootstrap = await getAppBootstrapData();
  const tenant = bootstrap?.currentTenant;
  if (!bootstrap || !tenant) {
    return null;
  }
  return { tenant };
}
```

```95:125:/Users/duhl/git/ui/apps/org-next/src/routes/_authed/campaigns/-campaigns.ts
export const updateCampaign = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      campaignId: z.string(),
      payload: z.object({ name: z.string().trim().min(1) }),
    }),
  )
  .handler(async ({ data }): Promise<Campaign | null> => {
    const ctx = await requireBootstrapWithTenant();
    if (!ctx) {
      return null;
    }
    try {
      return await putOrgApiJson<Campaign>(
        campaignMemberPath(ctx.tenant, data.campaignId),
        {
          campaign: { name: data.payload.name },
        },
      );
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "updateCampaign" },
      );
      throw error;
    }
  });
```

```127:159:/Users/duhl/git/ui/apps/org-next/src/routes/_authed/campaigns/-campaigns.ts
export const getCampaignDetail = createServerFn({ method: "GET" })
  .inputValidator(
    z.object({
      campaignId: z.string(),
    }),
  )
  .handler(async ({ data }) => {
    try {
      const campaign = await fetchCampaign({
        data: { campaignId: data.campaignId },
      });

      if (!campaign) {
        throw notFound();
      }

      return { campaign };
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      if (isNotFound(error)) {
        throw error;
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "getCampaignDetail" },
      );
      throw error;
    }
  });
```

```161:187:/Users/duhl/git/ui/apps/org-next/src/routes/_authed/campaigns/-campaigns.ts
export const createCampaign = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      name: z.string().trim().min(1),
    }),
  )
  .handler(async ({ data }) => {
    try {
      const campaign = await createCampaignForCurrentTenant({ data });

      if (!campaign) {
        throw new Error("Unable to create campaign");
      }

      return campaign;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "createCampaign" },
      );
      throw error;
    }
  });
```

**Other server fns in this file** (`fetchCampaignsList`, `createCampaignForCurrentTenant`, `fetchCampaign`) only use `requireBootstrapWithTenant()` and return `null` when unauthenticated; they do not call `redirect` to `/login` themselves.

